  %s3 = shufflevector <16 x i32> %a, <16 x i32> %s4, <16 x i32> <i32 0, i32 17, i32 2, i32 19, i32 4, i32 21, i32 6, i32 23, i32 8, i32 25, i32 10, i32 27, i32 12, i32 29, i32 14, i32 31>
  %add = add <16 x i32> %s3, %s4
